import{_ as s,c as a,a as i,o as n}from"./app-CEcM0piI.js";const l={};function d(t,e){return n(),a("div",null,e[0]||(e[0]=[i(`<p>作用域，即变量（变量作用域又称上下文）和函数生效（能被访问）的区域或集合 作用域决定了代码区块中变量和其他资源的可见性</p><ul><li><p>全局作用域 任何不在函数中或是大括号中声明的变量，都是在全局作用域下，全局作用域下声明的变量可以在程序的任意位置访问</p></li><li><p>函数作用域 函数作用域也叫局部作用域，如果一个变量是在函数内部声明的它就在一个函数作用域下面。这些变量只能在函数内部访问，不能在函数以外去访问</p></li><li><p>块级作用域 代码块的范围，如if、while或单大括号包裹的作用域 ES6引入了<code>let</code>和<code>const</code>关键字,和<code>var</code>关键字不同，在大括号中使用<code>let</code>和<code>const</code>声明的变量存在于块级作用域中。在大括号之外不能访问这些变量</p></li></ul><h3 id="词法作用域" tabindex="-1"><a class="header-anchor" href="#词法作用域"><span>词法作用域</span></a></h3><p>词法作用域，又叫静态作用域，变量被创建时就确定好了，而非执行阶段确定的。也就是说我们写好代码时它的作用域就确定了，<code>JavaScript</code> 遵循的就是词法作用域</p><h3 id="作用域链" tabindex="-1"><a class="header-anchor" href="#作用域链"><span>作用域链</span></a></h3><p>当在<code>Javascript</code>中使用一个变量的时候，首先<code>Javascript</code>引擎会尝试在当前作用域下去寻找该变量，如果没找到，再到它的上层作用域寻找，以此类推直到找到该变量或是已经到了全局作用域 如果在全局作用域里仍然找不到该变量，它就会在全局范围内隐式声明该变量(非严格模式下)或是直接报错</p><h2 id="变量提升" tabindex="-1"><a class="header-anchor" href="#变量提升"><span>变量提升</span></a></h2><p>function和var关键字都会变量提升</p><blockquote><p>[!NOTE] Title 函数内部声明变量是不能提升到全局的 函数内部赋值，实际上相当于在全局声明，是可以提升的</p></blockquote><p>var变量和函数同名变量会首先提升，函数提升会覆盖变量提升 变量和函数同名变量执行，执行函数报错</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>var a=1</span></span>
<span class="line"><span>function a(){</span></span>
<span class="line"><span>	console.log(2)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>console.log(a) //1</span></span>
<span class="line"><span>a() //未定义</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="数据类型" tabindex="-1"><a class="header-anchor" href="#数据类型"><span>数据类型</span></a></h1><h2 id="基础数据类型" tabindex="-1"><a class="header-anchor" href="#基础数据类型"><span>基础数据类型</span></a></h2><p>基础类型存储在栈内存 被引用或拷贝时，会创建一个完全相等的变量</p><ul><li>undefined</li><li>Null</li><li>Boolean</li><li>String</li><li>Number</li><li>Symbol</li><li>Biglnt</li></ul><h2 id="引用数据类型" tabindex="-1"><a class="header-anchor" href="#引用数据类型"><span>引用数据类型</span></a></h2><p>引用类型存储在堆内存 存储的是地址，多个引用指向同一个地址 这里会涉及一个“共享”的概念</p><ul><li>Object</li></ul><h2 id="深拷贝和浅拷贝" tabindex="-1"><a class="header-anchor" href="#深拷贝和浅拷贝"><span>深拷贝和浅拷贝</span></a></h2><p><strong>深拷贝</strong> 定义：创建一个新的对象，复制原对象的所有属性，包括引用类型，确保新对象与原对象完全独立，修改任何一方不会影响另一方。 实现方</p><ul><li>手写递归函数：遍历原对象，判断属性是否为对象，是则递归复制，否则直接赋值。</li><li>JSON.parse(JSON.stringify(obj))：简单高效，但不支持函数、undefined、Symbol等特殊类型，且无法处理循环引用。</li><li>使用第三方库：如Lodash的<code>cloneDeep</code>方法，功能强大，支持各种复杂数据结构。</li></ul><p><strong>浅拷贝</strong> -定义：创建新对象，复制原对象的第一层属性，对于引用类型属性，只复制引用，新旧对象共享同一内存地址，修改一方会影响另一方。<br> 实现方法</p><ul><li>Object.assign(target, source)：将源对象的属性复制到目标对象，只复制一层。</li><li>展开运算符<code>...</code>：如<code>let newObj = {...oldObj}</code>，适用于对象和数组，同样只进行浅拷贝。</li><li>数组的<code>slice()</code>或<code>concat()</code>方法：如<code>let newArr = oldArr.slice()</code>，仅对数组进行浅拷贝。</li></ul><h2 id="判断数据类型" tabindex="-1"><a class="header-anchor" href="#判断数据类型"><span>判断数据类型</span></a></h2><ol><li>typeof</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>typeof a</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>返回a的数据类型</p><p>对于引用数据类型只能判断出object，无法获得详细的 由于历史残留的问题null也是object</p><ol start="2"><li>instanceof</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>a instanceof A</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>判断a是否是A构造函数生成的对象</p><p>只能判断引用数据类型 instanceof是基于原型链实现的</p><p><code>getProtypeOf</code>函数是object对象上自带的函数，用于获取实例身上的原型</p><ol start="3"><li>Object.prototype.tostring() 获取对象身上的原型并转成字符串返回</li></ol><h2 id="类型转换" tabindex="-1"><a class="header-anchor" href="#类型转换"><span>类型转换</span></a></h2><h3 id="显式类型转换" tabindex="-1"><a class="header-anchor" href="#显式类型转换"><span>显式类型转换</span></a></h3><p>显示转换，即我们很清楚可以看到这里发生了类型的转变，常见的方法有：</p><ul><li>Number()转换的时候是很严格的，只要有一个字符无法转成数值，整个字符串就会被转为<code>NaN</code></li><li>parseInt()相比<code>Number</code>，没那么严格了，<code>parseInt</code>函数逐个解析字符，遇到不能转换的字符就停下来</li><li>String()可以将任意类型的值转化成字符串</li><li>Boolean()可以将任意类型的值转为布尔值</li></ul><h3 id="隐式转换" tabindex="-1"><a class="header-anchor" href="#隐式转换"><span>隐式转换</span></a></h3><p>我们这里可以归纳为两种情况发生隐式转换的场景：</p><ul><li><p>比较运算（<code>==</code>、<code>!=</code>、<code>&gt;</code>、<code>&lt;</code>）、<code>if</code>、<code>while</code>需要布尔值地方</p></li><li><p>算术运算（<code>+</code>、<code>-</code>、<code>*</code>、<code>/</code>、<code>%</code>） 除了上面的场景，还要求运算符两边的操作数不是同一类型</p></li><li><p>在需要布尔值的地方，就会将非布尔值的参数自动转为布尔值，系统内部会调用<code>Boolean</code>函数</p></li><li><p>遇到预期为字符串的地方，就会将非字符串的值自动转为字符串。具体规则是：先将复合类型的值转为原始类型的值，再将原始类型的值转为字符串</p></li></ul><h1 id="object" tabindex="-1"><a class="header-anchor" href="#object"><span>Object</span></a></h1><h2 id="和map的比较" tabindex="-1"><a class="header-anchor" href="#和map的比较"><span>和map的比较</span></a></h2><p>Object是最常用的一种引l用类型数据，可用于存储键值对的集合，在ECMAScript 1st里添加的 Map是键值对的集合，采用Hash结构存储，在EcMAScript2015版本里新增的</p><p><strong>相同点</strong></p><ol><li>都可以进行键值对的设置和添加</li></ol><p><strong>不同点</strong></p><table><thead><tr><th>不同点</th><th>Object</th><th>Map</th></tr></thead><tbody><tr><td>属性的设置和添加</td><td>可以直接设置，判断属性是否存在一般使用三等运算符和undefined比较，删除属性使用delete运算符</td><td>需要使用api</td></tr><tr><td>键的类型</td><td>String或者Symbol</td><td>可以是任意类型，包括对象，数组，函数等，不会进行类型转换。在添加键值对时，会通过严格相等（===）来判断键属性是否已存在。但是NaN是一个特例，在使用三等号判断两个NaN时会返回false，因此在将NaN设置为map的键时NaN会覆盖</td></tr><tr><td>键的顺序</td><td>1.对于大于等于0的整数，会按照大小进行排序，对于小数和负数<br>会当做字符串处理<br>2.对于String类型，按照定义的顺序进行输出<br>3.对于Symbol类型，会直接过滤掉，不会进行输出，<br>如果想要输出Symbol类型属性<br>通过Object.getOwnPropertySymbols(）方法</td><td>key是有序的，按照插入的顺序进行返回</td></tr><tr><td>获取属性数量</td><td>只能手动计算，通过object.keys0方法或者通过for...in循环统计</td><td>直接通过size属性访问</td></tr><tr><td>迭代器</td><td>不可以使用for...of迭代器遍历</td><td>可以使用for...of</td></tr><tr><td>JSON序列号</td><td>可以序列化</td><td>不可以序列化，使用JSON序列化返回的是一个空对象字符串</td></tr></tbody></table><p>适用场景</p><table><thead><tr><th>Object</th><th>Map</th></tr></thead><tbody><tr><td>仅做数据存储，并且属性仅为字符串或者Symbol</td><td>1.会频繁更新和删除键值对时</td></tr><tr><td>需要进行序列化转换为json传输时</td><td>存储大量数据时，尤其是key类型未知的情况下</td></tr><tr><td>当做一个对象的实例，需要保留自己的属性和方法时</td><td>需要频繁进行迭代处理<br></td></tr></tbody></table><h2 id="常见方法" tabindex="-1"><a class="header-anchor" href="#常见方法"><span>常见方法</span></a></h2><ol><li>Object.is ES5比较两个值是否相等，只有两个运算符：（==）和严格相等运算符（===） 他们都有缺点，前者会自动转换数据类型，后者的NaN不等于自身、以及+0等于-0。</li></ol><p>ES6提出了《同值相等》的算法来解决这个问题。Object.is就是部署了这个算法的新方法。它用来比较两个值是否严格相等，与===运算符的行为基本一致。</p><ol start="2"><li>Object.assign Object.assign()方法用于将源对象（source）的所有<strong>可枚举对象属性</strong>赋值到目标对象 可以有多个参数，第一个参数是目标对象，后面的对象都是源对象</li></ol><p>该方法的复制方式是浅拷贝，也就是说如果源对象的某个属性是引用类型的话目标对象复制到的该属性只是那个属性的引用</p><ol start="3"><li>Object.getProtoTypeOf() Object.getProtoTypeOfO方法返回参数对象的原型。这是获取原型对象的标准方法。</li></ol><p>和直接使用<code>对象.__proto__</code>作用一样，但是__proto__是一个内部属性，不应该直接操作</p><ol start="4"><li><p>Object.setProtypeOf() Object.setPrototypeOf方法为参数对象设置原型，返回该参数对象。它接受两个参数，第一个是现有对象，第二个是原型对象。</p></li><li><p>Object.create 生成一个实例</p></li></ol><p><strong>与new关键字的区别</strong> 使用new关键字生成实例对象时需要有构造函数（class） Object.create可以根据一个实例生成实例对象该方法接受一个对象作为参数，然后以它为原型，返回一个实例对象，该实例完全继承原型对象的属性</p><p>Object.create方法还可以接受第二个参数。该参数是一个属性描述对象，它所描述的对象属性，会添加到实例对象，作为该对象自身的属性</p><blockquote><p>[!warning] Title</p><ol><li>Object.create方法生成的新对象，动态继承了原型。在原型上添加或修改任何方法，会立刻反映在新对象之上。</li><li>Object.create方法生成的对象，继承了它的原型对象的构造函数。</li></ol></blockquote><ol start="6"><li><p>Object.getOwnProprotyNames() 方法返回一个数组，成员是参数对象本身的所有属性的键名，不包含继承的属性键名。</p></li><li><p>Object.prototype.hasOwnProperty() 对象实例的hasOwnProperty方法返回一个布尔值，用于判断某个属性定义在对象自身，还是定义在原型链上。</p></li><li><p>Object.getOwnPropotyDescriptor() 获取该属性的描述对象（使用defineProperty定义属性时的配置）。</p></li></ol><h1 id="_9-执行上下文和执行栈" tabindex="-1"><a class="header-anchor" href="#_9-执行上下文和执行栈"><span>9. 执行上下文和执行栈</span></a></h1><p>执行上下文是对<code>Javascript</code>代码执行环境的一种抽象概念，只要有<code>Javascript</code>代码运行，那么它就一定是运行在执行上下文中</p><p>执行上下文的类型分为三种：</p><ul><li>全局执行上下文：只有一个，浏览器中的全局对象就是 <code>window</code>对象，<code>this</code> 指向这个全局对象</li><li>函数执行上下文：存在无数个，只有在函数被调用的时候才会被创建，每次调用函数都会创建一个新的执行上下文</li><li>Eval 函数执行上下文：指的是运行在 <code>eval</code> 函数中的代码，很少用而且不建议使用</li></ul><p>只有全局上下文（的变量）能被其他任何上下文访问 可以有任意多个函数上下文，每次调用函数创建一个新的上下文，会创建一个私有作用域，函数内部声明的任何变量都不能在当前函数作用域外部直接访问</p><h3 id="生命周期" tabindex="-1"><a class="header-anchor" href="#生命周期"><span>生命周期</span></a></h3><p>执行上下文的生命周期包括三个阶段：创建阶段 → 执行阶段 → 回收阶段</p><h4 id="创建阶段" tabindex="-1"><a class="header-anchor" href="#创建阶段"><span>创建阶段</span></a></h4><p>创建阶段即当函数被调用，但未执行任何其内部代码之前</p><p>创建阶段做了三件事：</p><ol><li><p>确定 this 的值，也被称为 <code>This Binding</code><code>this</code>的值是在执行的时候才能确认，定义的时候不能确认</p></li><li><p>LexicalEnvironment（词法环境） 组件被创建 词法环境有两个组成部分：</p></li></ol><ul><li>全局环境：是一个没有外部环境的词法环境，其外部环境引用为<code>null</code>，有一个全局对象，<code>this</code> 的值指向这个全局对象</li><li>函数环境：用户在函数中定义的变量被存储在环境记录中，包含了<code>arguments</code> 对象，外部环境的引用可以是全局环境，也可以是包含内部函数的外部函数环境</li></ul><ol start="3"><li>VariableEnvironment（变量环境） 组件被创建 变量环境也是一个词法环境，因此它具有上面定义的词法环境的所有属性 在 ES6 中，词法环境和变量环境的区别在于前者用于存储函数声明和变量（ <code>let</code> 和 <code>const</code> ）绑定，而后者仅用于存储变量（ <code>var</code> ）绑定</li></ol><p>创建阶段，会在代码中扫描变量和函数声明，然后将函数声明存储在环境中 但变量会被初始化为<code>undefined</code>(<code>var</code>声明的情况下)和保持<code>uninitialized</code>(未初始化状态)(使用<code>let</code>和<code>const</code>声明的情况下) 这就是变量提升的实际原因</p><h4 id="执行阶段" tabindex="-1"><a class="header-anchor" href="#执行阶段"><span>执行阶段</span></a></h4><p>在这阶段，执行变量赋值、代码执行 如果 <code>Javascript</code> 引擎在源代码中声明的实际位置找不到变量的值，那么将为其分配 <code>undefined</code> 值</p><h4 id="回收阶段" tabindex="-1"><a class="header-anchor" href="#回收阶段"><span>回收阶段</span></a></h4><p>执行上下文出栈等待虚拟机回收执行上下文</p><h2 id="执行栈" tabindex="-1"><a class="header-anchor" href="#执行栈"><span>执行栈</span></a></h2><p>执行栈，也叫调用栈，具有 LIFO（后进先出）结构，用于存储在代码执行期间创建的所有执行上下文 当<code>Javascript</code>引擎开始执行你第一行脚本代码的时候，它就会创建一个全局执行上下文然后将它压到执行栈中 每当引擎碰到一个函数的时候，它就会创建一个函数执行上下文，然后将这个执行上下文压到执行栈中 引擎会执行位于执行栈栈顶的执行上下文(一般是函数执行上下文)，当该函数执行结束后，对应的执行上下文就会被弹出，然后控制流程到达执行栈的下一个执行上下文</p><h1 id="undefined和null的区别" tabindex="-1"><a class="header-anchor" href="#undefined和null的区别"><span>undefined和null的区别</span></a></h1><table><thead><tr><th></th><th>undefined</th><th>null</th></tr></thead><tbody><tr><td>表示</td><td>表示一个变量已声明但尚未赋值，或者对象属性不存在时的默认值。</td><td>表示一个变量明确地指向一个空值或不存在的对象。</td></tr><tr><td>typeof</td><td>-使用<code>typeof</code>操作符检查时，<code>undefined</code>的类型是<code>&quot;undefined&quot;</code>。</td><td>而<code>null</code>的类型则是<code>&quot;object&quot;</code>。这是一个历史遗留问题，在JavaScript最初实现时的一个bug，后来为了兼容性而保留下来了。</td></tr><tr><td>直接比较<code>null</code>和<code>undefined</code>（例如使用<code>==</code>）会返回<code>true</code>，因为两者都被视为等价于“缺失值”。但是，如果使用严格相等运算符<code>===</code>进行比较，则由于它们的类型不同而返回<code>false</code>。</td><td></td><td></td></tr></tbody></table><h1 id="数据类型-1" tabindex="-1"><a class="header-anchor" href="#数据类型-1"><span>数据类型</span></a></h1><p><strong>基本数据类型（Primitive Types）</strong> 存储在栈（stack）中的简单数据段：</p><ol><li><strong>Undefined</strong> - 表示未定义的值。</li><li><strong>Null</strong> - 表示空值或不存在的对象。</li><li><strong>Boolean</strong> - 包含<code>true</code>和<code>false</code>两个值。</li><li><strong>Number</strong> - 用于表示整数或浮点数。此外，还包括特殊的数值如<code>Infinity</code>、<code>-Infinity</code>和<code>NaN</code>。</li><li><strong>String</strong> - 用于表示文本数据，可以通过单引号、双引号或反引号定义。</li><li><strong>Symbol</strong> (ES6新增) - 表示独一无二的值，通常用来创建对象的唯一属性键。</li></ol><p>基本数据类型的值是不可改变的（immutable），每次操作都会创建一个新的值。</p><p><strong>引用数据类型（Reference Types）</strong> 存储在堆（heap）中的对象，实际的值存放在内存的一个新位置，而变量中存放的是指向这个位置的引用或指针。</p><ol><li><strong>Object</strong> - 是一种复杂的数据类型，它可以包含多个数据类型，支持属性和方法。包括普通对象、数组(<code>Array</code>)、函数(<code>Function</code>)、日期(<code>Date</code>)等。</li></ol><p>当操作引用数据类型时，实际上是在操作对象在内存中的地址，而不是直接操作数据本身。这意味着当你将一个对象赋值给另一个变量时，实际上是创建了一个新的引用指向同一个对象，因此修改其中一个变量会影响到另一个变量所指向的对象。</p><h3 id="主要区别" tabindex="-1"><a class="header-anchor" href="#主要区别"><span>主要区别</span></a></h3><ul><li><strong>存储方式</strong>：基本数据类型直接存储其值，而引用数据类型存储的是指向该值在内存中的地址的引用。</li><li><strong>比较方式</strong>：基本数据类型按值进行比较，只有当值相同时才认为两者相等；引用数据类型则比较的是它们在内存中的地址，即使两个对象的内容完全相同，只要它们不是同一个对象实例，在比较时也不会认为它们相等。</li><li><strong>传递方式</strong>：函数参数传递时，基本数据类型以值传递的方式传入，而引用数据类型是以引用传递的方式传入。</li></ul><h1 id="symbol" tabindex="-1"><a class="header-anchor" href="#symbol"><span>Symbol</span></a></h1><p>符号，相当于永不重复的符号，作为数据的唯一标识 用于解决重复命名冲突</p><p><strong>定义Symbol</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let a = Symbol()</span></span>
<span class="line"><span>let b = Symbol()</span></span>
<span class="line"><span>console.log(a) // Symbol</span></span>
<span class="line"><span>console.log(b) // Symbol</span></span>
<span class="line"><span>console.log(a == b) // false</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在定义Symbol时还可以附带自定义的描述： 使用Symbol上面的description属性来获取描述</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let a = Symbol(&#39;this a&#39;)</span></span>
<span class="line"><span>console.log(a) // Symbol(this a)</span></span>
<span class="line"><span>console.log(a.description) // this a</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>for函数</strong> for函数是用于添加Symbol的描述的，和直接使用<code>Symbol(描述)</code>不同的是：</p><ol><li>使用for定义是全局定义的，直接添加的是局部定义的</li><li>使用for指定描述时会先去内存中查看是否有相同描述的Symbol，如果有则新定义的Symbol就会指向这个Symbol（浅拷贝）</li><li>使用for定义的可以使用keyFor函数获取描述，相当于description，而直接定义的无法使用keyFor获取到</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let a = Symbol.for(&#39;aaa&#39;)</span></span>
<span class="line"><span>let b = Symbol.for(&#39;aaa&#39;)</span></span>
<span class="line"><span>console.log(a == b) // true</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>使用</strong></p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let user1={</span></span>
<span class="line"><span>	name:&quot;李四&quot;,</span></span>
<span class="line"><span>	key: Symbol()</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let user2 = {</span></span>
<span class="line"><span>	name:&quot;李四&quot;,</span></span>
<span class="line"><span>	key: Symbol()</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let grade = {</span></span>
<span class="line"><span>	[user1.key]: { js: 100, css: 89 }</span></span>
<span class="line"><span>	[user2.key]: { js: 35 css: 55 }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>console.log(grade[user1.key]); // { js: 100, css: 89 }</span></span>
<span class="line"><span>console.log(grade[user2.key]); // { js: 35 css: 55 }</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h1 id="json" tabindex="-1"><a class="header-anchor" href="#json"><span>JSON</span></a></h1><p>JSON常用的两个方法：</p><ol><li>stringify：将一个JavaScript对象或值转换为JSON字符串</li><li>parse：将JSON字符串转换为JavaScript对象</li></ol><h1 id="数组扁平化" tabindex="-1"><a class="header-anchor" href="#数组扁平化"><span>数组扁平化</span></a></h1><p>将多维数组降维成一维</p><h1 id="类数组" tabindex="-1"><a class="header-anchor" href="#类数组"><span>类数组</span></a></h1><p>它们不能直接调用数组的方法，但是又和数组比较类似，在某些特定的编程场景中会出现</p><p>类数组的场景：</p><ol><li>函数里面的参数对象arguments</li><li>用getElementsByTagName/ClassName/Name获得的HTMLCollection</li><li>用querySelector获得的NodeList</li></ol><h1 id="sort实现原理" tabindex="-1"><a class="header-anchor" href="#sort实现原理"><span>sort实现原理</span></a></h1><ol><li>当n&lt;=10 时，采用插入排序</li><li>当n&gt;10 时，采用三路快速排序</li><li>110&lt;n&lt;=1000，采用中位数作为哨兵元素</li><li>n&gt;1000，每隔200~215个元素挑出一个元素放到一个新数组中，然后对它排序，找到中间位置的数，以此作为中位数</li></ol>`,115)]))}const c=s(l,[["render",d]]),r=JSON.parse('{"path":"/front/principle/5/","title":"5 数据类型","lang":"zh-CN","frontmatter":{"title":"5 数据类型","createTime":"2025/06/19 15:11:06","permalink":"/front/principle/5/"},"readingTime":{"minutes":15.77,"words":4730},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/原理/5 数据类型.md","headers":[]}');export{c as comp,r as data};
